import React, { useState } from 'react';
import { Outlet, NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const NAV_ITEMS = [
  { path: 'dashboard',  icon: '⚡', label: 'Dashboard'  },
  { path: 'bookings',   icon: '📋', label: 'Bookings'   },
  { path: 'workers',    icon: '🔧', label: 'Workers'    },
  { path: 'approvals',  icon: '✅', label: 'Approvals', badge: true },
  { path: 'settlement', icon: '💸', label: 'Settlement' },
  { path: 'reviews',    icon: '⭐', label: 'Reviews'    },
  { path: 'customers',  icon: '👥', label: 'Customers'  },
];

export default function AdminLayout({ pendingCount = 0 }) {
  const { admin, logout } = useAuth();
  const navigate = useNavigate();
  const [collapsed, setCollapsed] = useState(false);

  const handleLogout = async () => {
    await logout();
    navigate('/login');
  };

  return (
    <div style={{ display: 'flex', minHeight: '100vh', background: '#080B0F', fontFamily: "'Syne', sans-serif" }}>

      {/* ── SIDEBAR ── */}
      <div style={{
        width: collapsed ? 68 : 220, background: '#0D1117',
        borderRight: '1px solid rgba(255,77,77,0.1)',
        display: 'flex', flexDirection: 'column',
        transition: 'width 0.25s ease', flexShrink: 0,
        position: 'sticky', top: 0, height: '100vh', overflowX: 'hidden',
      }}>
        {/* Brand */}
        <div style={{ padding: '24px 16px 20px', borderBottom: '1px solid rgba(255,255,255,0.06)' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
            <div style={{
              width: 40, height: 40, background: '#FF4D4D', borderRadius: 10,
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: 20, flexShrink: 0, boxShadow: '0 0 16px rgba(255,77,77,0.4)',
            }}>⚡</div>
            {!collapsed && (
              <div>
                <div style={{ fontSize: 18, fontWeight: 900, color: '#fff', letterSpacing: -0.5 }}>FixIt</div>
                <div style={{ fontSize: 9, fontWeight: 700, color: '#FF4D4D', letterSpacing: 2 }}>ADMIN PANEL</div>
              </div>
            )}
          </div>
        </div>

        {/* Nav Links */}
        <nav style={{ flex: 1, padding: '12px 10px', overflowY: 'auto' }}>
          {NAV_ITEMS.map(item => (
            <NavLink key={item.path} to={`/${item.path}`} style={{ textDecoration: 'none' }}>
              {({ isActive }) => (
                <div style={{
                  display: 'flex', alignItems: 'center', gap: 10,
                  padding: collapsed ? '10px 14px' : '10px 12px',
                  borderRadius: 10, marginBottom: 4, cursor: 'pointer',
                  background: isActive ? 'rgba(255,77,77,0.15)' : 'transparent',
                  border: `1px solid ${isActive ? 'rgba(255,77,77,0.3)' : 'transparent'}`,
                  transition: 'all 0.15s',
                  justifyContent: collapsed ? 'center' : 'flex-start',
                }}>
                  <span style={{ fontSize: 18, flexShrink: 0 }}>{item.icon}</span>
                  {!collapsed && (
                    <span style={{ fontSize: 13, fontWeight: isActive ? 700 : 600, color: isActive ? '#FF6B6B' : '#9CA3AF', flex: 1 }}>
                      {item.label}
                    </span>
                  )}
                  {!collapsed && item.badge && pendingCount > 0 && (
                    <div style={{
                      background: '#FF4D4D', color: '#fff', borderRadius: 999,
                      width: 18, height: 18, display: 'flex', alignItems: 'center',
                      justifyContent: 'center', fontSize: 10, fontWeight: 900,
                    }}>{pendingCount}</div>
                  )}
                </div>
              )}
            </NavLink>
          ))}
        </nav>

        {/* Collapse toggle */}
        <div style={{ padding: '10px', borderTop: '1px solid rgba(255,255,255,0.06)' }}>
          <div
            onClick={() => setCollapsed(c => !c)}
            style={{
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              height: 38, borderRadius: 9, cursor: 'pointer',
              background: 'rgba(255,255,255,0.04)', color: '#555A66',
              fontSize: 14, fontWeight: 700, gap: 6,
            }}
          >
            {collapsed ? '→' : '← Collapse'}
          </div>
        </div>
      </div>

      {/* ── MAIN AREA ── */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>

        {/* Top Bar */}
        <div style={{
          height: 60, background: '#0D1117', borderBottom: '1px solid rgba(255,255,255,0.06)',
          display: 'flex', alignItems: 'center', justifyContent: 'space-between',
          padding: '0 24px', flexShrink: 0,
          position: 'sticky', top: 0, zIndex: 50,
        }}>
          <div style={{ fontSize: 13, color: '#555A66' }}>
            Welcome back, <span style={{ color: '#FF6B6B', fontWeight: 700 }}>{admin?.name || 'Admin'}</span> 👋
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
            {/* Notification bell */}
            <div style={{
              width: 36, height: 36, background: 'rgba(255,255,255,0.04)',
              border: '1px solid rgba(255,255,255,0.08)', borderRadius: 9,
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: 16, cursor: 'pointer', position: 'relative',
            }}>
              🔔
              <div style={{
                position: 'absolute', top: 7, right: 7, width: 7, height: 7,
                background: '#FF4D4D', borderRadius: '50%',
              }} />
            </div>
            {/* Admin avatar */}
            <div style={{
              width: 36, height: 36, background: 'rgba(255,77,77,0.15)',
              border: '1.5px solid rgba(255,77,77,0.3)', borderRadius: 9,
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: 12, fontWeight: 900, color: '#FF6B6B',
            }}>
              {(admin?.name || 'A').charAt(0).toUpperCase()}
            </div>
            {/* Logout */}
            <div
              onClick={handleLogout}
              style={{
                fontSize: 12, fontWeight: 700, color: '#555A66', cursor: 'pointer',
                padding: '6px 14px', borderRadius: 8,
                border: '1px solid rgba(255,255,255,0.06)',
                background: 'rgba(255,255,255,0.02)',
              }}
            >
              Logout
            </div>
          </div>
        </div>

        {/* Page content rendered here */}
        <div style={{ flex: 1, overflowY: 'auto', padding: 24 }}>
          <Outlet />
        </div>
      </div>
    </div>
  );
}
